import{_ as e,o as r,c as i,ah as t}from"./chunks/framework.Bg572dcY.js";const p=JSON.parse('{"title":"可观测性","description":"","frontmatter":{"title":"可观测性","order":8},"headers":[],"relativePath":"server/distribute/micro/qos/observability/index.md","filePath":"server/distribute/micro/qos/observability/index.md"}'),h={name:"server/distribute/micro/qos/observability/index.md"};function l(n,a,s,o,d,c){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to “可观测性”">​</a></h1><p>可观测性是系统运维的核心能力，通过 Metrics（指标）、Logging（日志）、Tracing（链路追踪）了解系统内部状态。</p><h2 id="可观测性三大支柱" tabindex="-1">可观测性三大支柱 <a class="header-anchor" href="#可观测性三大支柱" aria-label="Permalink to “可观测性三大支柱”">​</a></h2><h3 id="metrics-指标" tabindex="-1">Metrics（指标） <a class="header-anchor" href="#metrics-指标" aria-label="Permalink to “Metrics（指标）”">​</a></h3><p>指标是数值型的测量值，反映系统的某个方面。指标类型：Counter（计数器）、Gauge（仪表盘）、Histogram（直方图）、Summary（摘要）。</p><p>指标示例：QPS、延迟（P50、P95、P99）、错误率、CPU 使用率。</p><h3 id="logging-日志" tabindex="-1">Logging（日志） <a class="header-anchor" href="#logging-日志" aria-label="Permalink to “Logging（日志）”">​</a></h3><p>日志是离散的事件记录，包含时间戳、级别、消息、上下文。日志级别：DEBUG、INFO、WARN、ERROR、FATAL。</p><p>结构化日志（JSON）方便机器解析，文本日志方便人类阅读。</p><h3 id="tracing-链路追踪" tabindex="-1">Tracing（链路追踪） <a class="header-anchor" href="#tracing-链路追踪" aria-label="Permalink to “Tracing（链路追踪）”">​</a></h3><p>链路追踪是请求在分布式系统中的路径，包含多个 Span（跨度）。链路追踪适合分析跨服务的调用链。</p><h2 id="监控系统" tabindex="-1">监控系统 <a class="header-anchor" href="#监控系统" aria-label="Permalink to “监控系统”">​</a></h2><h3 id="prometheus" tabindex="-1">Prometheus <a class="header-anchor" href="#prometheus" aria-label="Permalink to “Prometheus”">​</a></h3><p>Prometheus 是开源的监控系统，使用 Pull 模式采集指标。PromQL 是查询语言，支持聚合、过滤、计算。</p><h3 id="grafana" tabindex="-1">Grafana <a class="header-anchor" href="#grafana" aria-label="Permalink to “Grafana”">​</a></h3><p>Grafana 是开源的可视化平台，支持多种数据源（Prometheus、Elasticsearch）。</p><h2 id="日志系统" tabindex="-1">日志系统 <a class="header-anchor" href="#日志系统" aria-label="Permalink to “日志系统”">​</a></h2><h3 id="elk-stack" tabindex="-1">ELK Stack <a class="header-anchor" href="#elk-stack" aria-label="Permalink to “ELK Stack”">​</a></h3><p>Elasticsearch（存储和搜索）、Logstash（收集和转换）、Kibana（可视化）。</p><h3 id="loki" tabindex="-1">Loki <a class="header-anchor" href="#loki" aria-label="Permalink to “Loki”">​</a></h3><p>Loki 是 Grafana Labs 开发的日志系统，设计类似 Prometheus，不索引日志内容。</p><h2 id="链路追踪" tabindex="-1">链路追踪 <a class="header-anchor" href="#链路追踪" aria-label="Permalink to “链路追踪”">​</a></h2><h3 id="opentelemetry" tabindex="-1">OpenTelemetry <a class="header-anchor" href="#opentelemetry" aria-label="Permalink to “OpenTelemetry”">​</a></h3><p>OpenTelemetry 是可观测性的开放标准，整合了 Metrics、Logging、Tracing。</p><h3 id="jaeger" tabindex="-1">Jaeger <a class="header-anchor" href="#jaeger" aria-label="Permalink to “Jaeger”">​</a></h3><p>Jaeger 是 Uber 开源的链迹追踪系统，兼容 OpenTelemetry。</p><h2 id="告警系统" tabindex="-1">告警系统 <a class="header-anchor" href="#告警系统" aria-label="Permalink to “告警系统”">​</a></h2><h3 id="告警规则" tabindex="-1">告警规则 <a class="header-anchor" href="#告警规则" aria-label="Permalink to “告警规则”">​</a></h3><p>告警规则定义何时触发告警。Prometheus 告警规则：rate(http_requests_total[5m]) &gt; 100。</p><h3 id="告警路由" tabindex="-1">告警路由 <a class="header-anchor" href="#告警路由" aria-label="Permalink to “告警路由”">​</a></h3><p>Alertmanager 路由告警到不同的接收者（邮箱、钉钉、企业微信）。</p><h3 id="告警收敛" tabindex="-1">告警收敛 <a class="header-anchor" href="#告警收敛" aria-label="Permalink to “告警收敛”">​</a></h3><p>时间收敛、空间收敛、因果收敛。</p>',33)])])}const b=e(h,[["render",l]]);export{p as __pageData,b as default};
